use std::ffi::{CStr, CString};
use std::os::raw::{c_char, c_int};

#[repr(C)]
struct UserData {
    user_id: c_int,
    room_name: *const c_char,
}

extern "C" {
    fn process_users_batch(data_ptr: *const UserData, count: c_int) -> c_int;
}

fn main() -> std::result::Result<(), Box<dyn std::error::Error>> {
    let user_ids = vec![101, 205, 310];
    let room_names = vec!["general", "private_A", "lobby"];
    let num_users = user_ids.len() as c_int;

    let mut data: Vec<UserData> = Vec::with_capacity(user_ids.len());

    for i in 0..user_ids.len() {
        let room_c_str = match std::ffi::CString::new(room_names[i]) { 
            Ok(s) => s, 
            Err(_) => continue,
        };

        data.push(UserData {
            user_id: user_ids[i] as c_int,
            room_name: room_c_str.as_ptr(),
        });
    }

    let status = unsafe {
        process_users_batch(data.as_ptr(), num_users)
    };

    if status == 0 {
        println!("Successfully processed batch of users.");
    } else {
        println!("Failed to process user batch with status code: {}", status);
    }

    Ok(())
}

