use std::ffi::{CStr, CString};
use std::os::raw::{c_char, c_void};

type ResolverResult = i32;

extern "C" fn validate_record(id: *const c_char, data: *const c_char) -> ResolverResult {
    unsafe {
        let id_c_str = CStr::from_ptr(id);
        let data_c_str = CStr::from_ptr(data);

        if id_c_str.is_empty() || data_c_str.is_empty() {
            return -1;
        }

        let id_s = match id_c_str.to_str() {
            Ok(s) => s,
            Err(_) => return -1,
        };
        let data_s = match data_c_str.to_str() {
            Ok(s) => s,
            Err(_) => return -1,
        };

        if id_s.contains("fail") || data_s.contains("error") {
            return 0;
        } else if id_s.contains("success") && data_s.contains("ok") {
            return 1;
        } else {
            return -2;
        }
    }
}

fn main() {
    let success_id = CString::new(b"success_record").unwrap();
    let success_data = CString::new(b"validation_ok_data").unwrap();

    let fail_id = CString::new(b"fail_record").unwrap();
    let fail_data = CString::new(b"some_error_value").unwrap();

    let result1 = validate_record(success_id.as_ptr(), success_data.as_ptr());
    println!("Test 1 Result: {}", result1);

    let result2 = validate_record(fail_id.as_ptr(), fail_data.as_ptr());
    println!("Test 2 Result: {}", result2);
}

